    foreground: "#f3f4f6",
    accent: "oklch(0.588 0.217 264)",
    sidebar: "color-mix(in srgb, #030712 97%, white)",
    editor: "color-mix(in srgb, #030712 95%, white)",
    terminal: "#0a0a0a",
    statusBar: "color-mix(in srgb, #030712 90%, white)",
  },
};

const T3_LIGHT: Theme = {
  id: "t3-light",
  name: "T3 Light",
  isDark: false,
  fontFamily: FONT_SANS,
  fontSize: 14,
  colors: {
    background: "#ffffff",
    foreground: "#1f2937",
    accent: "oklch(0.488 0.217 264)",
    sidebar: "#f9fafb",
    editor: "#ffffff",
    terminal: "#1f2937",
    statusBar: "#f3f4f6",
  },
};

const T3_MIDNIGHT: Theme = {
  id: "t3-midnight",
  name: "T3 Midnight",
  isDark: true,
  fontFamily: FONT_SANS,
  fontSize: 14,
  colors: {
    background: "#0d0f1a",
    foreground: "#e2e8f0",
    accent: "oklch(0.65 0.24 264)",
    sidebar: "#0a0c16",
    editor: "#0f1120",
    terminal: "#070910",
    statusBar: "#0a0c16",
  },
};

const BUILT_IN_THEMES: ReadonlyArray<Theme> = [T3_DARK, T3_LIGHT, T3_MIDNIGHT];

export function getTheme(id: string): Theme {
  return BUILT_IN_THEMES.find((t) => t.id === id) ?? T3_DARK;
}

export function listThemes(): ReadonlyArray<Theme> {
  return BUILT_IN_THEMES;
}

