import { type Theme } from "../hooks/useTheme";
import { useTheme } from "../hooks/useTheme";

function ThemeSwatch({ theme }: { theme: Theme }) {
  return (
    <div
      className="flex h-8 w-full overflow-hidden rounded-md border border-border"
      aria-hidden="true"
    >
      {/* sidebar strip */}
      <div className="w-1/4 shrink-0" style={{ background: theme.colors.sidebar }} />
      {/* editor area with accent dot */}
      <div
        className="flex flex-1 items-center justify-center"
        style={{ background: theme.colors.editor }}
      >
        <div
          className="h-2.5 w-2.5 rounded-full"
          style={{ background: theme.colors.accent }}
        />
      </div>
    </div>
  );
}

export function ThemeSelector() {
  const { theme: currentTheme, setTheme, availableThemes } = useTheme();

  return (
    <div className="grid grid-cols-1 gap-2 sm:grid-cols-3" role="radiogroup" aria-label="Theme">
      {availableThemes.map((t) => {
        const selected = currentTheme.id === t.id;
        return (
          <button
            key={t.id}
            type="button"
            role="radio"
            aria-checked={selected}
            className={`flex flex-col gap-2 rounded-xl border p-3 text-left transition-colors ${
              selected
                ? "border-primary/60 bg-primary/8"
                : "border-border bg-background hover:bg-accent"
            }`}
            onClick={() => setTheme(t)}
          >
            <ThemeSwatch theme={t} />
            <div className="flex items-center justify-between gap-2">
              <span className="text-xs font-medium text-foreground">{t.name}</span>
              {selected ? (
                <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                  Active
                </span>
              ) : null}
            </div>
          </button>
        );
      })}
    </div>
  );
}

