import { useCallback, useEffect, useSyncExternalStore } from "react";
import { type Theme, getTheme, listThemes } from "@t3tools/shared/themes";

export type { Theme };

const STORAGE_KEY = "t3code:theme";

let listeners: Array<() => void> = [];
let lastSnapshot: Theme | null = null;

function emitChange() {
  for (const listener of listeners) listener();
}

function migrateStoredId(raw: string | null): string {
  // Migrate from the old "light" | "dark" | "system" values
  if (raw === "light") return "t3-light";
  if (raw === "dark" || raw === "system" || raw === null) return "t3-dark";
  return raw;
}

function getStoredId(): string {
  return migrateStoredId(localStorage.getItem(STORAGE_KEY));
}

function applyTheme(theme: Theme, suppressTransitions = false): void {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }

  // Toggle .dark class so inherited CSS variable defaults stay correct
  document.documentElement.classList.toggle("dark", theme.isDark);
  document.documentElement.style.setProperty("color-scheme", theme.isDark ? "dark" : "light");

  // Apply theme-specific color overrides via CSS custom properties
  const { colors } = theme;
  document.documentElement.style.setProperty("--background", colors.background);
  document.documentElement.style.setProperty("--foreground", colors.foreground);
  document.documentElement.style.setProperty("--primary", colors.accent);
  document.documentElement.style.setProperty("--ring", colors.accent);
  document.documentElement.style.setProperty("--t3-sidebar", colors.sidebar);
  document.documentElement.style.setProperty("--t3-editor", colors.editor);
  document.documentElement.style.setProperty("--t3-terminal", colors.terminal);
  document.documentElement.style.setProperty("--t3-status-bar", colors.statusBar);
  document.documentElement.style.setProperty("--theme-font-family", theme.fontFamily);
  document.documentElement.style.setProperty("--theme-font-size", `${theme.fontSize}px`);

  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent flash
applyTheme(getTheme(getStoredId()));

function getSnapshot(): Theme {
  const theme = getTheme(getStoredId());

  if (lastSnapshot && lastSnapshot.id === theme.id) {
    return lastSnapshot;
  }

  lastSnapshot = theme;
  return lastSnapshot;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Listen for storage changes from other tabs
  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      applyTheme(getTheme(getStoredId()), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    window.removeEventListener("storage", handleStorage);
  };
}

export function useTheme() {
  const theme = useSyncExternalStore(subscribe, getSnapshot);

  const resolvedTheme: "light" | "dark" = theme.isDark ? "dark" : "light";

  const setTheme = useCallback((next: Theme | string) => {
    const id = typeof next === "string" ? next : next.id;
    const resolved = getTheme(id);
    localStorage.setItem(STORAGE_KEY, id);
    applyTheme(resolved, true);
    emitChange();
  }, []);

  const availableThemes = listThemes();

  // Keep DOM in sync on mount/change
  useEffect(() => {
    applyTheme(theme);
  }, [theme]);

  return { theme, setTheme, availableThemes, resolvedTheme } as const;
}
